// Static reference data generated by tools/build-db.mjs from the LATAM client
// (see README). Loaded once at startup.

export type Slot = "top" | "mid" | "low" | "garment";
export const SLOTS: Slot[] = ["top", "mid", "low", "garment"];

export type Costume = {
  id: number;
  name: string;
  /** Sprite view id (the client's ClassNum, or recovered from the resource name
   *  when ClassNum is 0) — absent when the item has none. */
  view?: number;
  /** Visual slot(s) the item occupies (multi-slot costumes cover several). */
  slots: Slot[];
};

export type PaletteInfo = {
  count: number;
  /** Representative hex color per palette index (null when unsampled). */
  swatches: (string | null)[];
};

export type ClassInfo = {
  id: number;
  jt: string;
  name: string;
  group: string;
  race: "human" | "doram";
  /** Clothes-color palettes per gender; a missing gender has no palette files
   *  (gender-locked classes like Trovador/Musa have exactly one entry). */
  palettes: Partial<Record<"m" | "f", PaletteInfo>>;
  /** True when the class has no party icon in the client — unreleased on LATAM. */
  unreleased?: boolean;
};

export type HairSet = {
  styles: { n: number; colors: number }[];
  swatches: (string | null)[];
};

export type HairDb = Record<"human" | "doram", Record<"m" | "f", HairSet>>;

export type Db = {
  classes: ClassInfo[];
  hair: HairDb;
  costumes: Costume[];
};

export async function loadDb(): Promise<Db> {
  const [classes, hair, costumes] = await Promise.all([
    fetchJson<{ classes: ClassInfo[] }>("db/classes.json"),
    fetchJson<HairDb>("db/hair.json"),
    fetchJson<{ items: Costume[] }>("db/costumes.json"),
  ]);
  const items = costumes.items
    .slice()
    .sort((a, b) => a.name.localeCompare(b.name, "pt-BR") || a.id - b.id);
  // Drop classes unreleased on LATAM (no party icon) — they shouldn't appear in
  // the picker (or anywhere else).
  const released = classes.classes.filter((c) => !c.unreleased);
  return { classes: released, hair, costumes: items };
}

async function fetchJson<T>(path: string): Promise<T> {
  const res = await fetch(path);
  if (!res.ok) throw new Error(`${path}: HTTP ${res.status}`);
  return res.json() as Promise<T>;
}
